const Header = ({name1}) => {
  return (
    <div>
      <h1>{props.name1}</h1>
    </div>
  )
}
const Part = (part) => {
  return (
    <div>
      <p>
        {part.name}
        {part.exercises}

      </p>
    </div>
  );
}

const Content = (part) => {
  return (
    <div>

      <Part part={part[0]} />
      <Part part={part[1]} />
      <Part part={part[2]} />

    </div>
  );

}

const Total = (part) => {
  return (
    <p>Number of excercises: {part[0].exercise + part[1].exercise + part[2].exercise}</p>

  );

}


const App = () => {
  const course = {
    name1: 'Half Stack application development',
    part: [{
      name: 'Fundamentals of React',
      exercise:  10

    },

    {
  name: 'Using props to pass data',
  exercise : 7


    }, 
    {
      name:  'State of a component',
      excercise : 14

    }]
  }

  return(
    <div>
       <Header name1={course.name1} />

       <Content part = {course.part} />

      <Total part = {course.part}  />
    </div >
  )
}

export default App
